mapper.select:
	/* 이메일 중복 조회 */
    SELECT COUNT(*) 
    FROM MEMBER 
    WHERE MBR_EMAIL = #{email} 
      AND MBR_USE_YN = 'Y'

mapper.update:
	/* 회원 정보 수정 */
    UPDATE MEMBER
    SET MBR_NAME = #{mbrName},
        MBR_NICKNAME = #{mbrNickname},
        MBR_TELNO = #{mbrTelno},
        MBR_ZIP = #{mbrZip},
        MBR_ADDR = #{mbrAddr},
        MBR_DADDR = #{mbrDaddr}
    WHERE MBR_ID = #{mbrId}

mapper.select:
	/* 닉네임 중복 조회 */
    SELECT COUNT(*) 
    FROM MEMBER 
    WHERE MBR_NICKNAME = #{nickname} 
      AND MBR_USE_YN = 'Y'

/* 회원정보 조회 */
SELECT 
      MBR_ID, MBR_PASSWORD, MBR_NAME, MBR_NICKNAME, MBR_EMAIL, 
      MBR_TELNO, MBR_ZIP, MBR_ADDR, MBR_DADDR, MBR_PROVIDER_CD, 
      MBR_REFRESH_TOKEN, MBR_AUTH_CD, MBR_JOIN_DATE, MBR_LAST_LGN_DATE, MBR_USE_YN
FROM MEMBER
WHERE MBR_EMAIL = #{email} 
  AND MBR_USE_YN = 'Y';

mapper.insert:
/* 회원등록 */
INSERT INTO MEMBER (
      MBR_PASSWORD, MBR_NAME, MBR_NICKNAME, MBR_EMAIL, MBR_TELNO, 
      MBR_ZIP, MBR_ADDR, MBR_DADDR, MBR_PROVIDER_CD, MBR_AUTH_CD, 
      MBR_JOIN_DATE, MBR_USE_YN
) VALUES (
      #{mbrPassword}, #{mbrName}, #{mbrNickname}, #{mbrEmail}, #{mbrTelno}, 
      #{mbrZip}, #{mbrAddr}, #{mbrDaddr}, #{mbrProviderCd}, #{mbrAuthCd}, 
      NOW(), 'Y'
);

mapper.update:
/* 리프레시토큰 수정 */
UPDATE MEMBER
SET MBR_REFRESH_TOKEN = #{refreshToken}
WHERE MBR_ID = #{mbrId};

/* 마지막 로그인 일시 업데이트 */
UPDATE MEMBER
SET MBR_LAST_LGN_DATE = NOW()
WHERE MBR_ID = #{mbrId};
